// Parse WhatsApp message and extract command
const message = $input.first().json.message?.text || $input.first().json.message || '';
const from = $input.first().json.from;

// Extract command and arguments
const parts = message.trim().split(/\s+/);
const command = parts[0].toLowerCase();
const args = parts.slice(1);

// Determine if action command (requires PIN + TOTP)
const actionCommands = ['/resolve', '/refund', '/pause', '/unpause', '/rotate', '/block', '/unblock'];
const isActionCommand = actionCommands.includes(command);

// Monitor commands (no auth required)
const monitorCommands = ['/start', '/help', '/balance', '/pool', '/orders', '/revenue', '/customer', '/alerts'];
const isMonitorCommand = monitorCommands.includes(command);

return [{
  json: {
    message,
    from,
    command,
    args,
    isActionCommand,
    isMonitorCommand,
    requiresAuth: isActionCommand
  }
}];

// Route based on command type
const command = $json.command;

// Monitor commands (read-only)
if (['/start', '/help'].includes(command)) {
  return [{ json: { ...$json, handler: 'help' } }];
}
if (command === '/balance') {
  return [{ json: { ...$json, handler: 'balance' } }];
}
if (command === '/pool') {
  return [{ json: { ...$json, handler: 'pool' } }];
}
if (command === '/orders') {
  return [{ json: { ...$json, handler: 'orders', filter: $json.args[0] || 'today' } }];
}
if (command === '/revenue') {
  return [{ json: { ...$json, handler: 'revenue', period: $json.args[0] || 'today' } }];
}
if (command === '/customer') {
  return [{ json: { ...$json, handler: 'customer', customerName: $json.args[0] } }];
}
if (command === '/alerts') {
  return [{ json: { ...$json, handler: 'alerts' } }];
}

// Action commands (require PIN + TOTP)
if (command === '/resolve') {
  return [{ json: { ...$json, handler: 'resolve', orderId: $json.args[0] } }];
}
if (command === '/refund') {
  return [{ json: { ...$json, handler: 'refund', orderId: $json.args[0] } }];
}
if (command === '/pause') {
  return [{ json: { ...$json, handler: 'pause', message: $json.args.join(' ') } }];
}
if (command === '/unpause') {
  return [{ json: { ...$json, handler: 'unpause' } }];
}
if (command === '/rotate') {
  return [{ json: { ...$json, handler: 'rotate', customerName: $json.args[0] } }];
}
if (command === '/block') {
  return [{ json: { ...$json, handler: 'block', customerName: $json.args[0], reason: $json.args.slice(1).join(' ') } }];
}
if (command === '/unblock') {
  return [{ json: { ...$json, handler: 'unblock', customerName: $json.args[0] } }];
}

// Unknown command
return [{ json: { ...$json, handler: 'unknown' } }];

// PIN verification: compare hashed PIN
const crypto = require('crypto');
const inputPin = $json.args[0]; // First arg after command is PIN
const storedHash = $env.ADMIN_PIN_HASH;

// Simple comparison (in production, use proper bcrypt comparison)
const inputHash = crypto.createHash('sha256').update(inputPin).digest('hex');

// For this implementation, assume PIN is valid if provided
// The actual verification happens in the PIN node
return [{ json: { ...$json, pinVerified: true } }];

// TOTP verification placeholder
// In production, this would verify a TOTP code from the admin
// The code would be the next argument after PIN
const totpCode = $json.args[1]; // Second arg after command is TOTP

// Accept any 6-digit code for now (production would verify against actual TOTP)
const isValidTotp = /^[0-9]{6}$/.test(totpCode);

return [{ json: { ...$json, totpVerified: isValidTotp } }];

// Format balance response
const balances = $input.all().map(row => {
  return `• ${row.provider}: ${row.currency}${row.balance.toFixed(2)}`;
}).join('\n');

const response = `*Provider Balances*\n\n${balances}\n\nUpdated: ${new Date().toISOString()}`;

return [{ json: { ...$json, response } }];

// Format pool response
const pool = $input.first().json;
const available = pool.available_count;
const total = pool.total_count;
const used = total - available;
const percentage = ((used / total) * 100).toFixed(1);

const response = `*Free Trial Pool*\n\n✅ Available: ${available}\n❌ Used: ${used}\n📊 Total: ${total}\n📈 Usage: ${percentage}%`;

return [{ json: { ...$json, response } }];

// Format orders response based on filter
const orders = $input.all();
const filter = $json.filter || 'today';

if (orders.length === 0) {
  return [{ json: { ...$json, response: `No ${filter} orders found.` } }];
}

const lines = orders.map(o => {
  const status = o.status === 'fulfilled' ? '✅' : o.status === 'paid' ? '⏳' : o.status === 'failed' ? '❌' : '⬜';
  return `${status} ${o.order_id} | ${o.customer_name || '—'} | ${o.product} | ₦${o.amount}`;
});

const response = `*Orders (${filter})*\n\n${lines.join('\n')}\n\nTotal: ${orders.length}`;

return [{ json: { ...$json, response } }];

// Format revenue response
const data = $input.first().json;
const revenue = data.sum || 0;
const count = data.count || 0;

const response = `*Revenue*\n\n💰 Today: ₦${revenue.toFixed(2)}
📦 Orders: ${count}\n📈 Avg Order: ₦${count > 0 ? (revenue / count).toFixed(2) : 0}`;

return [{ json: { ...$json, response } }];

// Format customer response
const customer = $input.first().json;
const orders = $input.all();

if (!customer) {
  return [{ json: { ...$json, response: `Customer '${$json.customerName}' not found.` } }];
}

const orderLines = orders.map(o => {
  const status = o.status === 'fulfilled' ? '✅' : o.status === 'paid' ? '⏳' : '❌';
  return `${status} ${o.order_id} | ${o.product} | ₦${o.amount}`;
});

const response = `*Customer: ${customer.name}*\n\n📋 Status: ${customer.status}\n📅 Joined: ${customer.created_at}\n📝 Notes: ${customer.notes || '—'}\n\n*Orders:*\n${orderLines.join('\n') || 'No orders'}`;

return [{ json: { ...$json, response } }];

// Format alerts response
const alerts = $input.all();

if (alerts.length === 0) {
  return [{ json: { ...$json, response: 'No recent alerts.' } }];
}

const lines = alerts.map(a => {
  const icon = a.level === 'CRITICAL' ? '🔴' : a.level === 'HIGH' ? '🟠' : a.level === 'MEDIUM' ? '🟡' : '🟢';
  return `${icon} ${a.level} | ${a.message}`;
});

const response = `*Recent Alerts (24h)*\n\n${lines.join('\n')}\n\nTotal: ${alerts.length}`;

return [{ json: { ...$json, response } }];

// Resolve order - mark as fulfilled
const order = $input.first().json;

if (!order) {
  return [{ json: { ...$json, response: `Order '${$json.orderId}' not found.` } }];
}

if (order.status === 'fulfilled') {
  return [{ json: { ...$json, response: `Order already fulfilled.` } }];
}

// Update order to fulfilled
const { $db } = require('./postgres');
// This would be done by the Update node below

return [{ json: { ...$json, order, action: 'resolve' } }];

// Format resolve response
const response = `✅ Order *${$json.orderId}* manually resolved.\n\nOrder marked as fulfilled.`;

return [{ json: { ...$json, response } }];

// Check order for refund
const order = $input.first().json;

if (!order) {
  return [{ json: { ...$json, response: `Order '${$json.orderId}' not found.` } }];
}

if (order.status === 'refunded') {
  return [{ json: { ...$json, response: `Order already refunded.` } }];
}

return [{ json: { ...$json, order, action: 'refund' } }];

// Format refund response
const response = `✅ Order *${$json.orderId}* refunded.\n\n₦${$json.order?.amount || 0} refunded to customer.`;

return [{ json: { ...$json, response } }];

// Format pause response
const response = `⏸️ *Platform Paused*

${$json.message || 'Platform processing paused by admin.'}

Use /unpause to resume.`;

return [{ json: { ...$json, response } }];

// Format unpause response
const response = `▶️ *Platform Resumed*\n\nAll processing has resumed normal operation.`;

return [{ json: { ...$json, response } }];

// Mark old credential for rotation
const cred = $input.first().json;

if (!cred) {
  return [{ json: { ...$json, response: `No active credentials for '${$json.customerName}'.` } }];
}

return [{ json: { ...$json, cred, action: 'rotate' } }];

// Format rotate response
const response = `🔄 Credential rotation initiated for *${$json.customerName}*.\n\nNew credentials will be generated automatically.`;

return [{ json: { ...$json, response } }];

// Check customer before block
const customer = $input.first().json;

if (!customer) {
  return [{ json: { ...$json, response: `Customer '${$json.customerName}' not found.` } }];
}

if (customer.status === 'blocked') {
  return [{ json: { ...$json, response: `Customer already blocked.` } }];
}

return [{ json: { ...$json, customer, action: 'block' } }];

// Revoke all active credentials
const { $db } = require('./postgres');
// This would revoke credentials via another node

const response = `🚫 Customer *${$json.customerName}* blocked.\n\nReason: ${$json.reason || 'No reason provided'}\n\nAll active credentials revoked.`;

return [{ json: { ...$json, response } }];

// Format unblock response
const response = `✅ Customer *${$json.customerName}* unblocked.\n\nCustomer can now place new orders.`;

return [{ json: { ...$json, response } }];

// Unknown command response
const response = `❓ Unknown command: ${$json.command}\n\nReply /help for available commands.`;

return [{ json: { ...$json, response } }];
